namespace sv_82889427ed834ddf838f5a9d9ad5e0da.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped per circuit — each user gets independent warehouse selection.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-A", Name = "Warehouse A – East" },
        new() { Id = "WH-B", Name = "Warehouse B – West" },
        new() { Id = "WH-C", Name = "Warehouse C – Central" },
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_82889427ed834ddf838f5a9d9ad5e0da.Services;

/// <summary>
/// Scoped per circuit. Manages low-stock polling and publishes count changes
/// so both the Dashboard page and the sidebar AlertBadge stay in sync.
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentAlertCount { get; private set; }
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
    }

    /// <summary>Simulates a database query for low-stock items.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Ref-counted start: the first subscriber spins up the timer.
    /// Called by components that want live polling (Dashboard, AlertBadge).
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    /// <summary>
    /// Ref-counted stop: polling halts when the last subscriber leaves.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _timer = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        // Fire immediately on first subscribe, then every 10 s.
        await RefreshAsync();

        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                await RefreshAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task RefreshAsync()
    {
        CurrentAlertCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
    }
}

@using sv_82889427ed834ddf838f5a9d9ad5e0da.Services
@inject WarehouseState WarehouseState
@rendermode InteractiveServer

<div class="d-flex align-items-center">
    <label class="me-2 text-nowrap mb-0 fw-semibold" for="warehouseSelect">Warehouse:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }
}

@using sv_82889427ed834ddf838f5a9d9ad5e0da.Services
@implements IDisposable
@inject InventoryAlertService AlertService
@rendermode InteractiveServer

@if (AlertService.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentAlertCount</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += HandleAlertCountChanged;
    }

    private void HandleAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= HandleAlertCountChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_82889427ed834ddf838f5a9d9ad5e0da.Services
@implements IDisposable
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 36rem;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Current warehouse ID: <code>@WarehouseState.CurrentWarehouseId</code>
        </p>

        <div class="d-flex align-items-center gap-2 mt-3">
            <span class="fs-5">Low-Stock Alerts:</span>
            @if (_alertCount > 0)
            {
                <span class="badge bg-danger fs-6">@_alertCount items</span>
            }
            else
            {
                <span class="badge bg-success fs-6">All stocked</span>
            }
        </div>

        <small class="text-muted d-block mt-2">
            Auto-refreshes every 10 seconds. Last check: @_lastCheck.ToString("T")
        </small>
    </div>
</div>

@code {
    private int _alertCount;
    private DateTime _lastCheck = DateTime.Now;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertDataArrived;
        AlertService.StartPolling();
    }

    private void OnWarehouseChanged()
    {
        // Warehouse switched — restart polling so the first tick fires immediately.
        AlertService.StopPolling();
        AlertService.StartPolling();
        InvokeAsync(StateHasChanged);
    }

    private void OnAlertDataArrived()
    {
        _alertCount = AlertService.CurrentAlertCount;
        _lastCheck = DateTime.Now;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertDataArrived;
        AlertService.StopPolling();
    }
}

